+        if (ex.getType() == folly::AsyncSocketException::TIMED_OUT) {
+          ++it;
+          continue;
+        }
+        TENZIR_DEBUG("dropping client {} after probe error: {}", peer,
+                     ex.what());
+        disconnected = true;
+      }
+      if (disconnected) {
+        TENZIR_DEBUG("dropping disconnected client {}", peer);
+        active_clients_->fetch_sub(1, std::memory_order_relaxed);
         it = clients.erase(it);
+      } else {
